/**
 * Defines the possible abi call signatures.
 */
export type Arc4BoxContractSignatures = keyof Arc4BoxContractTypes['methods']
/**
 * Defines the possible abi call signatures for methods that return a non-void value.
 */
export type Arc4BoxContractNonVoidMethodSignatures = keyof Arc4BoxContractTypes['methods'] extends infer T ? T extends keyof Arc4BoxContractTypes['methods'] ? MethodReturn<T> extends void ? never : T  : never : never
/**
 * Defines an object containing all relevant parameters for a single call to the contract.
 */
export type CallParams<TArgs> = Expand<
  Omit<AppClientMethodCallParams, 'method' | 'args' | 'onComplete'> &
    {
      /** The args for the ABI method call, either as an ordered array or an object */
      args: Expand<TArgs>
    }
>
/**
 * Maps a method signature from the Arc4BoxContract smart contract to the method's arguments in either tuple or struct form
 */
export type MethodArgs<TSignature extends Arc4BoxContractSignatures> = Arc4BoxContractTypes['methods'][TSignature]['argsObj' | 'argsTuple']
/**
 * Maps a method signature from the Arc4BoxContract smart contract to the method's return type
 */
export type MethodReturn<TSignature extends Arc4BoxContractSignatures> = Arc4BoxContractTypes['methods'][TSignature]['returns']

/**
 * Defines the shape of the keyed box state of the application.
 */
export type BoxKeysState = Arc4BoxContractTypes['state']['box']['keys']



